+// Heading renderer for QMarkdown
+// Ensure header content is properly escaped when HTML is disabled to prevent XSS (CVE-2025-43954)
+module.exports = function heading(tokens, idx, options, env, self) {
+  var token = tokens[idx];
+  var level = token.tag.slice(1);
+  var content = '';
+
+  // collect inline content
+  for (var i = idx + 1; i < tokens.length; i++) {
+    if (tokens[i].type === 'heading_close') break;
+    if (tokens[i].type === 'inline') {
+      content = tokens[i].content;
+      break;
+    }
+  }
+
+  // If the markdown-it instance has HTML disabled, escape header content to prevent XSS.
+  // We avoid depending on external utilities to keep this change minimal and self-contained.
+  var mdHasHtml = (token && token.map === undefined) ? false : true;
+  if (typeof (tokens[idx].level) !== 'undefined') {
+    // no-op, keep compatibility; actual detection below uses state if available
+  }
+  if (env && env.md && env.md.options && env.md.options.html === false) {
+    // simple and safe HTML escaping for header content
+    content = String(content)
+      .replace(/&/g, '&amp;')
+      .replace(/</g, '&lt;')
+      .replace(/>/g, '&gt;')
+      .replace(/"/g, '&quot;')
+      .replace(/'/g, '&#39;');
+  }
+
+  // generate id from content (slugify is project util)
+  var id = options.slugify ? options.slugify(content) : '';
+
+  return '<h' + level + (id ? ' id="' + id + '"' : '') + '>' + content + '</h' + level + '>';
+};
