+import React from "react";
+
+type Props = {
+  html: string;
+  width?: number;
+  height?: number;
+  // Whether the caller requires same-origin access for the embed (only set to true
+  // in controlled situations). Default false to follow least privilege.
+  allowSameOrigin?: boolean;
+};
+
+export default function Embedded({
+  html,
+  width = 300,
+  height = 200,
+  allowSameOrigin = false,
+}: Props) {
+  // Build a safe srcdoc from user-provided html by parsing and re-constructing
+  // a new document. Do NOT inject the original HTML verbatim.
+  const buildSafeSrcdoc = (inputHtml: string) => {
+    try {
+      const parser = new DOMParser();
+      const doc = parser.parseFromString(inputHtml, "text/html");
+      const iframe = doc.querySelector("iframe");
+      if (!iframe) {
+        // No iframe -> show escaped textual representation
+        return `<html><body><pre>${escapeHtml(inputHtml)}</pre></body></html>`;
+      }
+
+      // Only extract a few safe attributes from the provided iframe.
+      const src = iframe.getAttribute("src") || "";
+      const title = iframe.getAttribute("title") || "";
+      const allow = iframe.getAttribute("allow") || "";
+      const sandbox = iframe.getAttribute("sandbox") || "";
+
+      // Whitelist of acceptable sandbox tokens. Do NOT enable allow-same-origin
+      // unless the caller explicitly requests it via allowSameOrigin.
+      const allowedSandboxTokens = new Set<string>([
+        "allow-forms",
+        "allow-pointer-lock",
+        "allow-popups",
+        "allow-modals",
+        "allow-downloads",
+        "allow-presentation",
+        "allow-scripts",
+      ]);
+
+      const requestedTokens = sandbox
+        .split(/\s+/)
+        .map((t) => t.trim())
+        .filter(Boolean);
+
+      const finalSandbox = requestedTokens
+        .filter((t) => allowedSandboxTokens.has(t) || (t === "allow-same-origin" && allowSameOrigin))
+        .join(" ");
+
+      // Sanitize allow list to a small set of feature tokens.
+      const allowedAllowTokens = new Set<string>([
+        "geolocation",
+        "microphone",
+        "camera",
+        "clipboard-read",
+        "clipboard-write",
+      ]);
+      const finalAllow = allow
+        .split(";")
+        .map((s) => s.trim())
+        .filter(Boolean)
+        .map((grp) => grp.split(/\s+/).filter(Boolean))
+        .flat()
+        .filter((t) => allowedAllowTokens.has(t))
+        .join("; ");
+
+      // Compose safe srcdoc, escaping all attribute values.
+      return (
+        `<html><head><meta charset="utf-8"></head>` +
+        `<body style="margin:0;padding:0;overflow:hidden;">` +
+        `<iframe src="${escapeAttr(src)}" title="${escapeAttr(title)}" ` +
+        `sandbox="${escapeAttr(finalSandbox)}" allow="${escapeAttr(finalAllow)}" ` +
+        `style="border:0;margin:0;padding:0;width:100%;height:100%;"></iframe>` +
+        `</body></html>`
+      );
+    } catch (e) {
+      return `<html><body><pre>${escapeHtml(inputHtml)}</pre></body></html>`;
+    }
+  };
+
+  const srcdoc = buildSafeSrcdoc(html);
+
+  // The outer iframe sandbox should follow least privilege: include allow-same-origin
+  // only when explicitly requested.
+  const outerSandbox = allowSameOrigin ? "allow-scripts allow-same-origin" : "allow-scripts";
+
+  return (
+    <iframe
+      srcDoc={srcdoc}
+      width={width}
+      height={height}
+      title="excalidraw-embed"
+      sandbox={outerSandbox}
+      style={{ border: "0" }}
+    />
+  );
+}
+
+// Minimal HTML escaping for safe text node injection.
+const escapeHtml = (s: string) =>
+  s
+    .replace(/&/g, "&amp;")
+    .replace(/</g, "&lt;")
+    .replace(/>/g, "&gt;")
+    .replace(/"/g, "&quot;")
+    .replace(/'/g, "&#x27;");
+
+// Attribute escaper suitable for double-quoted attributes.
+const escapeAttr = (s: string) =>
+  s
+    .replace(/&/g, "&amp;")
+    .replace(/"/g, "&quot;")
+    .replace(/</g, "&lt;")
+    .replace(/>/g, "&gt;")
+    .replace(/\u0000/g, "");
