+'use strict';
+
+var RESERVED_KEYS = {
+  '__proto__': true,
+  'constructor': true,
+  'prototype': true
+};
+
+function isReservedKey(key) {
+  return key != null && RESERVED_KEYS[key];
+}
+
+// Safely get a property value. If the property name is a reserved key
+// return undefined instead of returning the underlying descriptor so that
+// expression-language consumers cannot reach constructors or prototypes.
+function safeGet(obj, key) {
+  if (isReservedKey(key)) return undefined;
+  if (obj == null) return undefined;
+  return obj[key];
