+import java.net.InetAddress;
+import java.net.URI;
+import java.net.UnknownHostException;
+
+/**
+ * Minimal utility to validate user-provided URLs to avoid SSRF.
+ * Ensures scheme is http/https and that the resolved address is not
+ * an internal / loopback / link-local / metadata address.
+ */
+public final class UrlValidationUtils {
+
+  private UrlValidationUtils() {
+  }
+
+  public static void validateRemoteEndpoint(String endpoint) {
+    if (endpoint == null || endpoint.trim().isEmpty()) {
+      throw new IllegalArgumentException("Endpoint must not be empty");
+    }
+
+    URI uri;
+    try {
+      uri = URI.create(endpoint);
+    } catch (IllegalArgumentException e) {
+      throw new IllegalArgumentException("Endpoint is not a valid URI", e);
+    }
+
+    String scheme = uri.getScheme();
+    if (scheme == null || !(scheme.equalsIgnoreCase("http") || scheme.equalsIgnoreCase("https"))) {
+      throw new IllegalArgumentException("Endpoint scheme must be http or https");
+    }
+
+    String host = uri.getHost();
+    if (host == null || host.trim().isEmpty()) {
+      // URI.create may accept URIs without explicit host (e.g., file: or relative); reject those
+      throw new IllegalArgumentException("Endpoint must contain a valid host");
+    }
+
+    // Reject obvious loopback hostnames early
+    if ("localhost".equalsIgnoreCase(host) || "loopback".equalsIgnoreCase(host)) {
+      throw new IllegalArgumentException("Endpoint host is not allowed");
+    }
+
+    InetAddress[] addrs;
+    try {
+      addrs = InetAddress.getAllByName(host);
+    } catch (UnknownHostException e) {
+      // If the host cannot be resolved, be conservative and reject it
+      throw new IllegalArgumentException("Endpoint host cannot be resolved", e);
+    }
+
+    for (InetAddress addr : addrs) {
+      if (isPrivateOrLocalAddress(addr)) {
+        throw new IllegalArgumentException("Endpoint resolves to a local or otherwise restricted address: " + addr.getHostAddress());
+      }
+    }
+  }
+
+  private static boolean isPrivateOrLocalAddress(InetAddress addr) {
+    if (addr.isAnyLocalAddress() || addr.isLoopbackAddress() || addr.isLinkLocalAddress() || addr.isMulticastAddress()) {
+      return true;
+    }
+
+    if (addr.isSiteLocalAddress()) {
+      // covers 10/8, 172.16/12, 192.168/16 for IPv4
+      return true;
+    }
+
+    byte[] raw = addr.getAddress();
+    if (raw.length == 4) {
+      int b0 = raw[0] & 0xFF;
+      int b1 = raw[1] & 0xFF;
+
+      // 127.0.0.0/8
+      if (b0 == 127) {
+        return true;
+      }
+
+      // 169.254.0.0/16 (link-local / metadata ranges)
+      if (b0 == 169 && b1 == 254) {
+        return true;
+      }
+
+      // 100.64.0.0/10 Carrier Grade NAT
+      if (b0 == 100 && (b1 >= 64 && b1 <= 127)) {
+        return true;
+      }
+    } else if (raw.length == 16) {
+      // IPv6 checks:
+      // ::1 loopback
+      if (addr.isLoopbackAddress()) {
+        return true;
+      }
+      // Unique local addresses fc00::/7
+      int firstByte = raw[0] & 0xFF;
+      if ((firstByte & 0xFE) == 0xFC) {
+        return true;
+      }
+      // Link-local fe80::/10
+      if (firstByte == 0xFE && (raw[1] & 0xC0) == 0x80) {
+        return true;
+      }
+    }
+
+    // explicitly block cloud metadata IP commonly abused
+    if ("169.254.169.254".equals(addr.getHostAddress())) {
+      return true;
+    }
+
+    return false;
+  }
