+// Ensure populate entries are strictly validated against the list of allowed
+// top-level relations/fields. The previous implementation used substring
+// checks which could be abused (e.g. "not_author" containing "author").
+// This implementation:
+// - For string entries (comma or dot notation) only allows them if the
+//   top-level path (first segment before '.' or '[') is explicitly allowed.
+// - For arrays, filters each entry individually.
+// - For objects, only keeps keys that are explicitly allowed and applies
+//   the same filtering recursively for nested populate specifications.
+const topLevelFromEntry = (entry) => {
+  if (typeof entry !== 'string') return null;
+  // Trim and strip bracket/index style e.g. "author[posts]" or "author.posts"
+  const trimmed = entry.trim();
+  // take substring before first '.' or '['
+  const dotIndex = trimmed.indexOf('.');
+  const bracketIndex = trimmed.indexOf('[');
+  let end = trimmed.length;
+  if (dotIndex !== -1) end = Math.min(end, dotIndex);
+  if (bracketIndex !== -1) end = Math.min(end, bracketIndex);
+  return trimmed.slice(0, end);
+};
+
+const isTopLevelAllowed = (entry, allowed) => {
+  const top = topLevelFromEntry(entry);
+  if (!top) return false;
+  // exact match only
+  return allowed.includes(top);
+};
+
+const filterPopulate = (populate, allowed) => {
+  if (!populate) return populate;
+
+  if (typeof populate === 'string') {
+    return populate
+      .split(',')
+      .map((p) => p.trim())
+      .filter((p) => isTopLevelAllowed(p, allowed))
+      .join(',');
+  }
+
+  if (Array.isArray(populate)) {
+    return populate
+      .filter((p) => {
+        if (typeof p === 'string') return isTopLevelAllowed(p, allowed);
+        if (p && typeof p === 'object') {
+          // object entries like { author: { populate: 'profile' } }
+          return Object.keys(p).some((k) => allowed.includes(k));
+        }
+        return false;
+      })
+      .map((p) => {
