+/* CSRF protection middleware
+ * Adds a server-wide anti-CSRF token and enforces its presence for
+ * state-changing requests (POST/PUT/PATCH/DELETE).
+ *
+ * - Generates a random token at startup and stores it on the app instance.
+ * - Exposes GET /_csrf which returns JSON { csrfToken } so clients (UI)
+ *   can fetch the token and send it with state-changing requests.
+ * - Validates X-CSRF-Token header on unsafe methods and rejects requests
+ *   with a 403 status on mismatch/absence.
+ *
+ * This file is intentionally minimal and self-contained.
+ */
+'use strict';
+
+const crypto = require('crypto');
+
+module.exports = function setupCsrf(app) {
+  // Generate a global token per server process. This is a simple yet effective
+  // mitigation for CSRF in apps without per-session state.
+  const token = crypto.randomBytes(32).toString('hex');
+  app.set('csrfToken', token);
+
+  // Expose endpoint for UI to obtain the token. This should be fetched by
+  // client-side code (e.g. single-page app) and set on X-CSRF-Token for
+  // subsequent state-changing requests.
+  app.get('/_csrf', function (req, res) {
+    res.json({ csrfToken: app.get('csrfToken') });
+  });
+
+  const unsafeMethods = new Set(['POST', 'PUT', 'PATCH', 'DELETE']);
+
+  // Middleware to validate CSRF token for unsafe HTTP methods.
+  app.use(function validateCsrf(req, res, next) {
+    if (!unsafeMethods.has(req.method)) {
+      return next();
+    }
+
+    // Accept token from X-CSRF-Token header.
+    const submitted = req.headers['x-csrf-token'];
+    const expected = app.get('csrfToken');
+    if (submitted && expected && submitted === expected) {
+      return next();
+    }
+
+    // Reject when missing or invalid.
+    res.status(403).send('Forbidden — invalid or missing CSRF token');
+  });
+};
+
